ALTER TABLE public.ai_provider_configs DROP CONSTRAINT IF EXISTS ai_provider_configs_provider_type_check;
ALTER TABLE public.ai_provider_configs ADD CONSTRAINT ai_provider_configs_provider_type_check CHECK (provider_type IN ('lovable', 'perplexity', 'firecrawl', 'openai', 'anthropic', 'gemini', 'replicate', 'custom', 'openrouter', 'kie', 'poyo', 'dashscope', 'geminigen'));